mapper.sql:
SELECT A.SBJCT_ID , A.CRS_ID , A.USER_ID , A.APLY_CRDTS , A.CNTNDAY_CNT , NVL(A.CNTN_MNTS_SUM, 0) AS CNTN_MNTS_SUM , NVL(A.CNTN_MNTS_DAY_AVG, 0) AS CNTN_MNTS_DAY_AVG , NVL(A.CNTN_MNTS_DAY_STND_DVTN, 0) AS CNTN_MNTS_DAY_STND_DVTN , NVL(A.CNTNDAY_INTVL_AVG, 0) AS CNTNDAY_INTVL_AVG , NVL(A.CNTNDAY_INTVL_STND_DVTN, 0) AS CNTNDAY_INTVL_STND_DVTN , NVL(A.WKEND_CNTNRT, 0) AS WKEND_CNTNRT , NVL(A.WKDAYS_CNTNRT, 0) AS WKDAYS_CNTNRT , A.FRST_INQ_DTTM , A.MOD_DTTM , B.USERNM FROM TB_LMS_STATS_SUM_ATNDLC A JOIN TB_LMS_USR B ON A.USER_ID = B.USER_ID
AND B.DEPT_CD = #{deptCd}
WHERE A.SBJCT_ID = #{creYear} AND A.CRS_ID = #{creTerm}
AND ( LOWER(A.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(B.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )

mapper.select:
/* SQL ID : statisticsDAO.stdntlrnPrgrtStatusSelect 설 명 : 전체/운영과목 학습진도 현황(수강생수, 평균학습진도율) */ WITH SBJ_LIST AS ( SELECT A.SBJCT_YR , A.SBJCT_SMSTR , SMSTR.SMSTR_CHRT_ID , SMSTR.ORG_ID , A.DEPT_ID , A.SBJCT_ID , A.SBJCTNM , A.PROF_ID , A.DVCLAS_NO , A.DELYN FROM TB_LMS_SBJCT A JOIN TB_LMS_SMSTR_CHRT SMSTR ON A.SBJCT_REF_TYCD = 'SMSTR_CHRT' AND A.SMSTR_CHRT_ID = SMSTR.SMSTR_CHRT_ID WHERE 1=1 AND DELYN = 'N' ), WHOLE_STATUS AS ( SELECT COUNT(A.USER_ID) AS STD_CNT , SUM(A.PRGRT) AS SUM_PRGRT FROM TB_LMS_LRN_PRGRT A JOIN SBJ_LIST B ON A.SBJCT_ID = B.SBJCT_ID
AND B.ORG_ID = #{orgId}
), MY_SBJCT_STATUS AS ( SELECT COUNT(A.USER_ID) AS STD_CNT , SUM(A.PRGRT) AS SUM_PRGRT FROM TB_LMS_LRN_PRGRT A JOIN SBJ_LIST B ON A.SBJCT_ID = B.SBJCT_ID
AND B.ORG_ID = #{orgId}
AND B.PROF_ID = #{userId} ) SELECT A.STD_CNT AS WHOLE_STD_CNT , NVL( ROUND(A.SUM_PRGRT / A.STD_CNT, 2),0) AS WHOLE_AVG_LRN_PRGRT , B.STD_CNT AS MY_STD_CNT , NVL( ROUND(B.SUM_PRGRT / B.STD_CNT, 2),0) AS MY_AVG_LRN_PRGRT FROM WHOLE_STATUS A, MY_SBJCT_STATUS B

/* SQL ID : statisticsDAO.stdntLrnPrgrtList 설 명 : 학습자 학습진도 현황 목록 조회 */ WITH SBJ_LIST AS ( SELECT A.SBJCT_YR , A.SBJCT_SMSTR , A.SMSTR_CHRT_ID , SMSTR.ORG_ID , A.DEPT_ID , A.SBJCT_ID , A.SBJCTNM , A.DVCLAS_NO , A.DELYN FROM TB_LMS_SBJCT A JOIN TB_LMS_SMSTR_CHRT SMSTR ON A.SBJCT_REF_TYCD = 'SMSTR_CHRT' AND A.SMSTR_CHRT_ID = SMSTR.SMSTR_CHRT_ID WHERE 1=1 AND DELYN = 'N'
AND A.SBJCT_YR = #{sbjctYr}
AND A.SMSTR_CHRT_ID = #{smstrChrtId}
AND SMSTR.ORG_ID = #{orgId}
AND A.DEPT_ID = #{deptId}
AND A.SBJCT_ID = #{sbjctId}
),
OPEN_WK_LIST AS ( SELECT ORG.ORGNM , A.* , B.LCTR_WKNO_SCHDL_ID FROM SBJ_LIST A JOIN TB_LMS_LCTR_WKNO_SCHDL B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' AND (FN_DT() > B.LCTR_WKNO_EYMD OR FN_DT() BETWEEN B.LCTR_WKNO_SYMD AND B.LCTR_WKNO_EYMD) LEFT JOIN TB_LMS_ORG ORG ON A.ORG_ID = ORG.ORG_ID ),
OPEN_WK_CNT AS ( SELECT SBJCT_ID , COUNT(*) AS OPEN_WK_CNT FROM OPEN_WK_LIST GROUP BY SBJCT_ID ),
STD_LIST AS ( SELECT A.SBJCT_ID , B.USER_ID , USR.USERNM , B.SCYR , USR.STDNT_NO FROM SBJ_LIST A JOIN TB_LMS_ATNDLC B ON A.SBJCT_ID = B.SBJCT_ID JOIN TB_LMS_USER USR ON B.USER_ID = USR.USER_ID WHERE 1=1 AND B.AUDITYN = 'N' ) SELECT ROW_NUMBER() OVER(ORDER BY A.SBJCT_YR ASC, A.SBJCT_SMSTR ASC, A.ORGNM DESC, A.DEPTNM ASC, A.SBJCTNM) AS LINE_NO , A.* FROM ( SELECT
OWL.SBJCT_YR , OWL.SBJCT_SMSTR , OWL.ORGNM
, NVL(DEPT.DEPTNM, '—') AS DEPTNM , OWL.SBJCTNM , OWL.DVCLAS_NO , STS.USER_ID , USR.USERNM , USR.SCYR , OWK.OPEN_WK_CNT
, COUNT(CASE WHEN NVL(STS.PRGRT,0) > 0 THEN STS.LCTR_WKNO_SCHDL_ID END ) AS LRN_WK_CNT , ROUND( COUNT(CASE WHEN NVL(STS.PRGRT,0) > 0 THEN STS.LCTR_WKNO_SCHDL_ID END ) / NULLIF(OWK.OPEN_WK_CNT, 0) * 100 , 2) AS PRGRT FROM OPEN_WK_LIST OWL JOIN OPEN_WK_CNT OWK ON OWL.SBJCT_ID = OWK.SBJCT_ID JOIN STD_LIST USR ON OWL.SBJCT_ID = USR.SBJCT_ID LEFT JOIN TB_LMS_BYWK_USER_LRN_STS STS ON OWL.LCTR_WKNO_SCHDL_ID = STS.LCTR_WKNO_SCHDL_ID AND USR.USER_ID = STS.USER_ID LEFT JOIN TB_LMS_DEPT DEPT ON OWL.DEPT_ID = DEPT.DEPT_ID WHERE 1=1
AND PRGRT > 0
AND PRGRT >= 0
AND PRGRT >= #{searchFrom}
AND PRGRT < #{searchTo}
GROUP BY OWL.SBJCT_ID , OWL.ORG_ID , OWL.SBJCT_YR , OWL.SBJCT_SMSTR , OWL.ORGNM , DEPT.DEPT_ID , DEPTNM , OWL.SBJCTNM , OWL.DVCLAS_NO , STS.USER_ID , USR.USERNM , USR.SCYR , OWK.OPEN_WK_CNT ) A ORDER BY LINE_NO DESC

/* SQL ID : statisticsDAO.listLrnPrgrtStatusByDept 설 명 : 학습진도관리 > 학과별 학습진도율 목록 조회 */ WITH DEPT_LIST AS ( SELECT SMSTR.ORG_ID , ORG.ORGNM , PRGRT.SBJCT_ID , SBJ.DEPT_ID , DEPT.DEPTNM , SBJ.SBJCT_YR , SBJ.SBJCT_SMSTR , SMSTR.SMSTR_CHRT_ID , SBJ.DELYN , PRGRT.PRGRT , PRGRT.USER_ID FROM TB_LMS_LRN_PRGRT PRGRT JOIN TB_LMS_SBJCT SBJ ON SBJ.SBJCT_REF_TYCD = 'SMSTR_CHRT' AND PRGRT.SBJCT_ID = SBJ.SBJCT_ID JOIN TB_LMS_SMSTR_CHRT SMSTR ON SBJ.SMSTR_CHRT_ID = SMSTR.SMSTR_CHRT_ID JOIN TB_LMS_ORG ORG ON SMSTR.ORG_ID = ORG.ORG_ID LEFT JOIN TB_LMS_DEPT DEPT ON SBJ.DEPT_ID = DEPT.DEPT_ID WHERE 1=1 AND SBJ.DELYN = 'N'
AND SBJ.SBJCT_YR = #{sbjctYr}
AND SBJ.SMSTR_CHRT_ID = #{smstrChrtId}
AND ORG.ORG_ID = #{orgId}
AND DEPT.DEPT_ID = #{deptId}
AND SBJ.SBJCT_ID = #{sbjctId}
) SELECT ROW_NUMBER() OVER(ORDER BY A.SBJCT_YR, A.SBJCT_SMSTR, A.DEPTNM) AS LINE_NO , A.* FROM ( SELECT ORG_ID , ORGNM , DEPT_ID , DEPTNM , SBJCT_YR , SBJCT_SMSTR , COUNT(USER_ID) AS ALL_USER_CNT , AVG(PRGRT) AS AVG_PRGRT_BY_DEPT FROM DEPT_LIST GROUP BY ORG_ID, ORGNM, DEPT_ID, DEPTNM, SBJCT_YR , SBJCT_SMSTR )A

/* SQL ID : StatisticsDAO.listContentStatisticsAll 설 명 : 학습자 수강 통계 주차별 목록 */
SELECT ROW_NUMBER() OVER(ORDER BY A.USERNM) AS LINE_NO , A.* FROM (
) A

