SELECT A.SBJCT_ID , A.CRS_ID , A.USER_ID , A.SBJCT_LCTR_WKNO , A.APLY_CRDTS , A.CNTNDAY_CNT , A.CONN_DAY_SUM , A.CONN_TM , NVL(A.CNTN_MNTS_SUM, 0) AS CNTN_MNTS_SUM , NVL(A.CNTN_MNTS_DAY_AVG, 0) AS CNTN_MNTS_DAY_AVG , NVL(A.CNTN_MNTS_DAY_STND_DVTN, 0) AS CNTN_MNTS_DAY_STND_DVTN , NVL(A.CNTNDAY_INTVL_AVG, 0) AS CNTNDAY_INTVL_AVG , NVL(A.CNTNDAY_INTVL_STND_DVTN, 0) AS CNTNDAY_INTVL_STND_DVTN , NVL(A.WKEND_CNTNRT, 0) AS WKEND_CNTNRT , NVL(A.WKDAYS_CNTNRT, 0) AS WKDAYS_CNTNRT , A.FRST_INQ_DTTM , A.MOD_DTTM , B.USERNM FROM TB_STAT_STDY_WEEKSUM A JOIN TB_LMS_USR B ON A.USER_ID = B.USER_ID
AND B.DEPT_CD = #{deptCd}
WHERE A.SBJCT_ID = #{creYear} AND A.CRS_ID = #{creTerm}
AND ( LOWER(A.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(B.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )

