mapper.sql:
SELECT A.SBJCT_ID , A.CRS_ID , A.CRS_ID , A.DVCLAS_NO , A.USER_ID , A.SBJCT_ID , A.SBJCTNM , A.APLY_CRDTS , A.CNTNDAY_CNT , NVL(A.CNTN_MNTS_SUM, 0) AS CNTN_MNTS_SUM , NVL(A.CNTN_MNTS_DAY_AVG, 0) AS CNTN_MNTS_DAY_AVG , NVL(A.CNTN_MNTS_DAY_STND_DVTN, 0) AS CNTN_MNTS_DAY_STND_DVTN , NVL(A.CNTNDAY_INTVL_AVG, 0) AS CNTNDAY_INTVL_AVG , NVL(A.CNTNDAY_INTVL_STND_DVTN, 0) AS CNTNDAY_INTVL_STND_DVTN , NVL(A.WKEND_CNTNRT, 0) AS WKEND_CNTNRT , NVL(A.WKDAYS_CNTNRT, 0) AS WKDAYS_CNTNRT , A.FRST_INQ_DTTM , A.MOD_DTTM , B.USERNM FROM STATS_BYSBJCT A JOIN TB_LMS_USR B ON A.USER_ID = B.USER_ID
AND B.DEPT_CD = #{deptCd}
JOIN TB_LMS_SBJCT C ON A.SBJCT_ID = C.SBJCT_ID
AND C.UNIV_CD = #{uniCd}
AND C.UNIV_GBNCD = #{univGbn}
AND C.SBJCT_ID = #{crsCreCd}
LEFT JOIN SBJCT_PROF D ON A.SBJCT_ID = D.SBJCT_ID AND D.PROF_TYCD = 'PROFESSOR' AND D.RPRSYN = 'Y' WHERE A.SBJCT_ID = #{creYear} AND A.CRS_ID = #{creTerm}
AND ( LOWER(A.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.CRS_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER((SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = D.USER_ID)) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )

mapper.select:
